    22→		return `[${positionToString(r.start)}/${positionToString(r.end)}]`;
    23→	}
    24→
    25→	function assertEqualRange(actual: vscode.Range, expected: vscode.Range, message?: string) {
    26→		assert.strictEqual(rangeToString(actual), rangeToString(expected), message);
